  { pattern: /(^|\/)fuse\./,                name: 'FuseBox config' },

  // TypeScript / transpiler configs
  { pattern: /(^|\/)tsconfig\.json$/,      name: 'TypeScript config' },
  { pattern: /(^|\/)babel\.config\./,      name: 'Babel config' },
