  { pattern: /(^|\/)deno\.jsonc?$/,        name: 'Deno config' },
  { pattern: /(^|\/)bunfig\.toml$/,        name: 'Bun config' },
  { pattern: /(^|\/)nitro\.config\./,      name: 'Nitro config' },
  { pattern: /(^|\/)wrangler\.(toml|json)$/, name: 'Wrangler config' },
  { pattern: /(^|\/)drizzle\.config\./,    name: 'Drizzle config' },

