  { pattern: /(^|\/)turbo\.json$/,         name: 'Turborepo config' },
  { pattern: /(^|\/)pnpm-workspace\.yaml$/, name: 'PNPM workspace' },
  { pattern: /(^|\/)lerna\.json$/,          name: 'Lerna monorepo' },
  { pattern: /(^|\/)nx\.json$/,             name: 'Nx monorepo' },
  { pattern: /(^|\/)rush\.json$/,           name: 'Rush monorepo' },

