              message: `Build script found in workspace (${pkgPath}): "${script}"`, findings: [],
            };
          }
        } catch (err) {
          console.error(`Error reading workspace package ${pkgPath}:`, err);
        }
      }
    }

    const indicator = findBuildIndicator(tree);
    if (indicator) {
      return {
        checkId, status: 'pass', confidence: 'medium',
        message: `${indicator.name} found — build step likely configured`,
        findings: [],
      };
    }

    const hasTsConfig = tree?.some(p => /(^|\/)tsconfig\.json$/.test(p));
    const hasTypeScriptFiles = tree?.some(p => /\.([cm]?ts|tsx)$/.test(p) && !/\.d\.[cm]?ts$/.test(p));
    const hasTypesDep = !!(rootPkg?.devDependencies?.typescript || rootPkg?.dependencies?.typescript || rootPkg?.peerDependencies?.typescript);
    const expectsBuild = expectsCompiledOutput(rootPkg);

    const isPureJS = !hasTsConfig && !hasTypeScriptFiles && !hasTypesDep && !expectsBuild;

    if (isPureJS && ['library', 'framework', 'tool', 'server', 'unknown'].includes(repoType)) {
      return {
        checkId, status: 'not-applicable', confidence: 'medium',
        message: 'Pure JS runtime project — no build step required', findings: [],
      };
    }

    if (rootPkg && (hasTsConfig || hasTypeScriptFiles || hasTypesDep || expectsBuild)) {
      return {
        checkId, status: 'fail', confidence: 'high',
        message: 'Project appears to require compilation but no build script was found',
        findings: [{ file: 'package.json', issue: 'Missing build script for TypeScript/compilation step' }],
      };
    }

    if ((hasTsConfig || hasTypeScriptFiles) && !rootPkg) {
      return {
        checkId, status: 'check-it', confidence: 'medium',
        message: 'TypeScript indicators found but package.json could not be read',
        findings: [{ file: 'package.json', issue: 'Unable to verify build script due to unreadable package.json' }],
      };
    }

    return {
      checkId, status: 'check-it', confidence: 'low',
      message: 'Unable to determine if a build step is needed',
      findings: [{ file: 'package.json', issue: 'No build script or recognizable build configuration found' }],
    };

  } catch (err) {
    console.error('Build-step specialist error:', err);
    return {
      checkId, status: 'check-it', confidence: 'low',
      message: `Error: ${err.message}`,
      findings: [{ file: 'package.json', issue: err.message }],
    };
  }
